mapper.select:
/* com.erns.es.log.mapper.UserLogDAO.getList */
SELECT B.* FROM ( SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM ( SELECT AA.LOG_DATE , AA.MEMB_SEQ AS USER_SEQ , AA.LOG_TYPE , AA.SITE_TYPE , AA.MEMB_ID AS USER_ID , AA.MEMB_IP AS USER_IP
, UUR.MEMB_NAME AS USER_NAME
FROM T_MEMB_LOG_H AA LEFT OUTER JOIN T_MEMB_INF UUR ON AA.MEMB_SEQ = UUR.MEMB_SEQ
ORDER BY AA.LOG_DATE DESC, AA.SITE_TYPE, AA.MEMB_SEQ ) A ) B
WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

mapper.insert:
/* com.erns.es.log.mapper.UserLogDAO.insert */

INSERT INTO T_MEMB_LOG_H (
	LOG_DATE, MEMB_SEQ, LOG_TYPE, SITE_TYPE
	, MEMB_ID, MEMB_IP, LOG_JSON
)
VALUES (
	to_char(now(), 'YYYY-MM-DD HH24:MI:SS.MS')
	, #{userSeq	, jdbcType=INTEGER}
	, #{logType	, jdbcType=VARCHAR}
	, #{siteType, jdbcType=VARCHAR}

	, #{userId	, jdbcType=VARCHAR}
	, #{userIp	, jdbcType=VARCHAR}
	, #{logJson	, jdbcType=VARCHAR}
)

mapper.select:
/* com.erns.es.log.mapper.UserLogDAO.loadJson */

SELECT

FROM T_MEMB_LOG_H AA

	AND AA.LOG_DATE		= #{logDate}
	AND AA.MEMB_SEQ		= #{userSeq}
	AND AA.LOG_TYPE		= #{logType}
